const LOCAL_TEST_HOSTS = new Set(["127.0.0.1", "localhost"]); const CONTACT_EMAIL = "hello@rushconnectandcare.com.au"; function showFormStatus(form, message, type = "info") { let status = form.querySelector("[data-form-status]"); if (!status) { status = document.createElement("p"); status.className = `form-status form-status-${type}`; status.setAttribute("data-form-status", ""); status.setAttribute("role", "status"); status.setAttribute("aria-live", "polite"); form.append(status); } status.className = `form-status form-status-${type}`; status.textContent = message; } function getEndpoint(form) { if (LOCAL_TEST_HOSTS.has(window.location.hostname)) { return "/__form_test__"; } const configuredKey = form.dataset.formEndpoint; const configured = configuredKey ? window.RCC_CONFIG?.[configuredKey] : window.RCC_CONFIG?.formEndpoint; return configured || form.getAttribute("action") || ""; } function buildMailtoBody(form) { const entries = []; const fields = Array.from(form.elements).filter((field) => { if (!field.name || field.disabled) { return false; } if (field.type === "hidden" || field.type === "submit" || field.name === "botcheck") { return false; } if ((field.type === "checkbox" || field.type === "radio") && !field.checked) { return false; } return true; }); for (const field of fields) { const label = field .closest("label") ?.querySelector("span") ?.textContent?.trim() || field.name; const value = field.value?.trim(); if (!value) { continue; } entries.push(`${label}: ${value}`); } entries.push(""); entries.push(`Page: ${window.location.href}`); return entries.join("\n"); } function openMailFallback(form) { const subject = form.querySelector('input[name="_subject"]')?.value?.trim() || form.querySelector('input[name="form_type"]')?.value?.trim() || "Rush Connect & Care enquiry"; const body = buildMailtoBody(form); const mailtoUrl = `mailto:${CONTACT_EMAIL}?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`; window.location.assign(mailtoUrl); } async function handleFormSubmit(event) { event.preventDefault(); const form = event.currentTarget; const submitButton = form.querySelector('button[type="submit"]'); const isLocalTest = LOCAL_TEST_HOSTS.has(window.location.hostname); const endpoint = getEndpoint(form); if (!endpoint || endpoint.includes("YOUR_")) { showFormStatus( form, "This form is not available right now. We are opening an email draft so you can still send your enquiry.", "error" ); openMailFallback(form); return; } submitButton?.setAttribute("disabled", "disabled"); showFormStatus(form, "Sending your message...", "info"); try { if (isLocalTest) { const response = await fetch(endpoint, { method: "POST", headers: { Accept: "application/json" }, body: new FormData(form) }); if (!response.ok) { throw new Error(`Form request failed with status ${response.status}`); } } else { await fetch(endpoint, { method: "POST", mode: "no-cors", body: new FormData(form) }); } const successUrl = form.dataset.successUrl || window.RCC_CONFIG?.formSuccessUrl || "thank-you.html"; window.location.assign(successUrl); } catch { showFormStatus( form, "We could not send the form directly. We are opening an email draft so your enquiry can still be sent to hello@rushconnectandcare.com.au.", "error" ); openMailFallback(form); } finally { submitButton?.removeAttribute("disabled"); } } document.addEventListener("DOMContentLoaded", () => { document.querySelectorAll("[data-rcc-form]").forEach((form) => { if (new URLSearchParams(window.location.search).get("form-error") === "1") { showFormStatus( form, "We could not send the form directly. Please use the phone or email options below if needed.", "error" ); } form.addEventListener("submit", handleFormSubmit); }); });
